package controllers

import javax.inject._
import play.api.mvc._
import scala.io.Source
import scala.util.{Try, Using}
import java.io.File
import java.nio.file.{Path, Paths}

@Singleton
class FileController @Inject()(val controllerComponents: ControllerComponents) extends BaseController {

  private val BASE_UPLOAD_DIR: Path = Paths.get("uploads").toAbsolutePath.normalize()

  def serveFile(filename: String): Action[AnyContent] = Action { implicit request: Request[AnyContent] =>
    // Reject obviously malicious input early
    if (filename == null || filename.isEmpty) {
      BadRequest("Filename must not be empty.")
    } else if (filename.contains("\u0000")) {
      BadRequest("Invalid filename.")
    } else {
      // Resolve the requested path against the base directory and canonicalize
      val requestedPath: Path = BASE_UPLOAD_DIR.resolve(filename).normalize().toAbsolutePath

      // Enforce that the resolved path is strictly within the base upload directory
      if (!requestedPath.startsWith(BASE_UPLOAD_DIR)) {
        Forbidden("Access denied: path traversal detected.")
      } else {
        val file = requestedPath.toFile

        // Additional safety checks
        if (!file.exists()) {
          NotFound(s"File not found.")
        } else if (!file.isFile) {
          BadRequest("Requested path is not a regular file.")
        } else if (!file.canRead) {
          Forbidden("File is not readable.")
        } else {
          // Verify canonical path as an additional layer of defense (resolves symlinks)
          val canonicalPath = Paths.get(file.getCanonicalPath)
          val canonicalBase = Paths.get(BASE_UPLOAD_DIR.toFile.getCanonicalPath)

          if (!canonicalPath.startsWith(canonicalBase)) {
            Forbidden("Access denied: symlink traversal detected.")
          } else {
            Using(Source.fromFile(file, "UTF-8")) { source =>
              val content = source.mkString
              Ok(content).as(guessContentType(file.getName))
            }.recover {
              case _: java.io.FileNotFoundException =>
                NotFound("File not found.")
              case e: Exception =>
                InternalServerError("Error reading file.")
            }.get
          }
        }
      }
    }
  }

  private def guessContentType(filename: String): String = {
    val extension = filename.lastIndexOf('.') match {
      case -1 => ""
      case i  => filename.substring(i + 1).toLowerCase
    }
    extension match {
      case "html" | "htm" => "text/html; charset=utf-8"
      case "css"          => "text/css; charset=utf-8"
      case "js"           => "application/javascript; charset=utf-8"
      case "json"         => "application/json; charset=utf-8"
      case "xml"          => "application/xml; charset=utf-8"
      case "txt"          => "text/plain; charset=utf-8"
      case "csv"          => "text/csv; charset=utf-8"
      case "md"           => "text/markdown; charset=utf-8"
      case _              => "application/octet-stream"
    }
  }
}